INSERT INTO `partners` VALUES (7,'Bánh Tráng Chị Hoa','{\"must_try\": [\"Bánh tráng nướng trứng cút\", \"Bánh tráng nướng phô mai\"], \"price_range\": \"10k - 25k\"}','16:00 - 23:00',2,8,'','',NULL,''),(8,'Bánh Tráng Anh Tú','{\"must_try\": [\"Bánh tráng nướng tôm khô\", \"Bánh tráng cuộn\"], \"price_range\": \"15k - 30k\"}','17:00 - 22:30',2,8,'','',NULL,''),(9,'Hải Sản Cô Ba','{\"must_try\": [\"Ghẹ rang me\", \"Ốc hương xào dừa\", \"Tôm nướng muối ớt\"], \"price_range\": \"150k - 500k\"}','17:00 - 01:00',2,9,'','',NULL,''),(10,'Chè Nguyên','{\"must_try\": [\"Chè khúc bạch\", \"Chè 3 màu\", \"Nước mía ép\"], \"price_range\": \"20k - 45k\"}','08:00 - 23:00',2,10,'','',NULL,''),(11,'Phở Ký','{\"must_try\": [\"Phở bò tái nạm\", \"Hủ tiếu bò\"], \"price_range\": \"45k - 65k\"}','05:00 - 10:00',2,13,'','',NULL,''),(12,'Bún Bò Cô Hương','{\"must_try\": [\"Bún bò Huế giò heo\", \"Bún bò chả cua\"], \"price_range\": \"50k - 70k\"}','05:30 - 10:30',2,13,'','',NULL,''),(13,'Hải Sản Năm Phước','{\"must_try\": [\"Ghẹ rang me\", \"Mực nhồi thịt hấp\", \"Tôm nướng muối ớt\"], \"price_range\": \"150k - 500k\"}','10:00 - 23:00',2,8,'Chào mừng bạn đến Hải Sản Năm Phước! Quán chúng tôi chuyên các món hải sản tươi sống nguyên con, đặc biệt là ghẹ rang me và mực nhồi thịt hấp. Giá cả hợp lý, phục vụ từ 10 giờ sáng đến 11 giờ đêm.','https://maps.app.goo.gl/demo-hai-san',NULL,''),(14,'Bún Bò Huế Dì Tám','{\"must_try\": [\"Bún bò đặc biệt\", \"Bún giò heo\", \"Bánh mì chấm\"], \"price_range\": \"40k - 80k\"}','06:00 - 10:00',2,8,'Bún Bò Huế Dì Tám — hơn 30 năm giữ nguyên hương vị truyền thống. Nước dùng hầm xương bò 12 tiếng, cay đậm đà, ăn kèm rau sống tươi. Quán mở từ 6 giờ sáng, thường hết hàng trước 10 giờ!','',NULL,''),(15,'Chè Thái Cô Lan','{\"must_try\": [\"Chè Thái đặc biệt\", \"Trà sữa trân châu\", \"Sinh tố bơ\"], \"price_range\": \"20k - 45k\"}','08:00 - 22:00',2,8,'Giải nhiệt ngay với ly chè Thái mát lạnh của Cô Lan! Topping phong phú: thạch dừa, trân châu, đậu đỏ, kem béo. Chỉ 25.000đ một ly lớn, phục vụ cả ngày.','https://facebook.com/demo-che-thai',NULL,''),(16,'Super Baka','{\"must_try\": [], \"price_range\": \"\"}','',1,14,'Lãnh đạo những con bò','http://localhost:5173/api/pois/scan/?code=14',5,'Ê hông có đâu');
