INSERT INTO `poi_media` VALUES (9,'https://res.cloudinary.com/difapxo01/video/upload/v1774650882/bcsd/tts-audio/pho-am-thuc-vinh-khanh_vi.mp3?v=1774650882','vi','mien_nam','TTS',1,8,'Vĩnh Khánh là con phố ẩm thực nổi tiếng bậc nhất Quận 4, TP. HCM. Nơi đây quy tụ hàng trăm quán ăn đặc sản từ hải sản tươi sống, bún bò, hủ tiếu cho đến các món ăn vặt đường phố. Không khí nhộn nhịp từ sáng đến đêm khuya thu hút cả người dân địa phương lẫn du khách thập phương..',''),(11,'https://res.cloudinary.com/difapxo01/video/upload/v1774632007/bcsd/tts-audio/quan-hai-san-em-vinh-khanh_vi.mp3','vi','mien_nam','TTS',1,9,'Khu ẩm thực hải sản đêm nổi tiếng nhất Quận 4 với các món ghẹ rang me, ốc hương xào, tôm nướng muối ớt được chế biến tươi ngon từ hải sản nhập trực tiếp mỗi ngày. Ngồi vỉa hè, không khí đường phố đặc trưng Sài Gòn.',''),(12,'https://res.cloudinary.com/difapxo01/video/upload/v1774631681/bcsd/tts-audio/goc-che-nuoc-ep-trai-cay_vi.mp3','vi','mien_nam','TTS',1,10,'Điểm dừng chân quen thuộc của dân địa phương sau bữa ăn với hơn 30 loại chè truyền thống Nam Bộ: chè đậu xanh bột báng, chè khúc bạch, chè 3 màu... cùng các loại nước ép trái cây nhiệt đới tươi mát, mở cửa từ sáng đến đêm.',''),(13,'https://res.cloudinary.com/difapxo01/video/upload/v1774631560/bcsd/tts-audio/chua-vinh-khanh-co_vi.mp3','vi','mien_nam','TTS',1,11,'Ngôi chùa hơn 150 tuổi nằm giữa lòng phố ẩm thực Vĩnh Khánh, là nơi người dân địa phương và tiểu thương đến thắp hương cầu bình an mỗi sáng sớm. Kiến trúc đặc trưng phong cách Nam Bộ, mái ngói đỏ, cổng tam quan uy nghiêm.',''),(15,'https://res.cloudinary.com/difapxo01/video/upload/v1774631599/bcsd/tts-audio/cong-chao-pho-vinh-khanh_vi.mp3','vi','mien_nam','TTS',1,12,'Cổng chào biểu tượng của tuyến phố ẩm thực đêm Vĩnh Khánh, được thiết kế với đèn LED rực rỡ. Là điểm check-in nổi tiếng và cũng là điểm khởi đầu lý tưởng để khám phá toàn bộ tuyến phố ẩm thực. Sáng đèn từ 18:00 - 24:00.',''),(16,'https://res.cloudinary.com/difapxo01/video/upload/v1774631892/bcsd/tts-audio/khu-bun-bo-pho-sang_vi.mp3','vi','mien_nam','TTS',1,13,'áááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááá',''),(18,'https://res.cloudinary.com/difapxo01/video/upload/v1774650905/bcsd/tts-audio/pho-am-thuc-vinh-khanh_ko.mp3?v=1774650905','ko','','TTS',1,8,'Vinh Khanh은 도시 4군에서 가장 유명한 요리 거리입니다. HCM. 이곳에는 신선한 해산물, 쇠고기 국수, 국수부터 길거리 간식까지 수백 개의 전문 레스토랑이 모여 있습니다. 아침부터 늦은 밤까지 분주한 분위기가 곳곳에서 현지인과 관광객을 끌어 모으고 있습니다.','? 빈칸 푸드 스트리트'),(20,'https://res.cloudinary.com/difapxo01/video/upload/v1774631568/bcsd/tts-audio/chua-vinh-khanh-co_ko.mp3','ko','','TTS',1,11,'150년이 넘는 역사를 지닌 이 탑은 빈칸(Vinh Khanh) 요리 거리 중심부에 위치해 있으며, 현지 주민과 소규모 사업체들이 매일 이른 아침 향을 피우고 평화를 기원하는 곳입니다. 건축물은 붉은 기와지붕, 장엄한 3문으로 이루어진 전형적인 남부 스타일의 건축물입니다.','빈칸코(Vinh Khanh Co) 파고다'),(21,'https://res.cloudinary.com/difapxo01/video/upload/v1774650309/bcsd/tts-audio/quan-hai-san-em-vinh-khanh_en.mp3?v=1774650309','en','','TTS',1,9,'The most famous night seafood food area in District 4 with dishes of roasted crab with tamarind, stir-fried snails, grilled shrimp with salt and chili, prepared fresh from seafood imported directly every day. Sitting on the sidewalk, the street atmosphere is typical of Saigon. (updated)',''),(22,'https://res.cloudinary.com/difapxo01/video/upload/v1774632013/bcsd/tts-audio/quan-hai-san-em-vinh-khanh_ja.mp3','ja','','TTS',1,9,'4 区で最も有名な夜のシーフード フード エリア。毎日直輸入の新鮮な魚介類を使用して、タマリンド添えカニのロースト、カタツムリの炒め物、塩と唐辛子を添えたエビのグリルなどの料理を提供します。歩道に座っていると、サイゴンらしい街並みの雰囲気が漂います。',''),(23,'https://res.cloudinary.com/difapxo01/video/upload/v1774632016/bcsd/tts-audio/quan-hai-san-em-vinh-khanh_ko.mp3','ko','','TTS',1,9,'매일 직수입한 신선한 해산물을 이용해 타마린드를 곁들인 게구이, 달팽이 볶음, 소금과 칠리를 곁들인 새우구이 등을 선보이는 4군에서 가장 유명한 야식 해산물 지역입니다. 보도에 앉아 있으면 전형적인 사이공의 거리 분위기를 느낄 수 있습니다.',''),(24,'https://res.cloudinary.com/difapxo01/video/upload/v1774632020/bcsd/tts-audio/quan-hai-san-em-vinh-khanh_zh.mp3','zh','','TTS',1,9,'第四区最著名的夜间海鲜美食区，罗望子烤蟹、炒田螺、盐辣烤虾等菜肴，均采用每天直接进口的海鲜新鲜烹制。坐在人行道上，街道氛围是典型的西贡。',''),(25,'https://res.cloudinary.com/difapxo01/video/upload/v1774650911/bcsd/tts-audio/pho-am-thuc-vinh-khanh_zh.mp3?v=1774650911','zh','','TTS',1,8,'永庆 (Vinh Khanh) 是市第四区最著名的美食街。肥厚型心肌病。这里汇聚了数百家特色餐厅，从新鲜海鲜、牛肉面、面条到街头小吃。从早到晚的热闹气氛吸引着当地人和来自各地的游客。','? 永庆美食街'),(26,'https://res.cloudinary.com/difapxo01/video/upload/v1774631894/bcsd/tts-audio/khu-bun-bo-pho-sang_en.mp3','en','','TTS',1,13,'aaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa aaaaaaaaaaaa',''),(27,'https://res.cloudinary.com/difapxo01/video/upload/v1774631896/bcsd/tts-audio/khu-bun-bo-pho-sang_ja.mp3','ja','','TTS',1,13,'ああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああああ',''),(28,'https://res.cloudinary.com/difapxo01/video/upload/v1774631898/bcsd/tts-audio/khu-bun-bo-pho-sang_ko.mp3','ko','','TTS',1,13,'aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa 아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아아',''),(29,'https://res.cloudinary.com/difapxo01/video/upload/v1774631901/bcsd/tts-audio/khu-bun-bo-pho-sang_zh.mp3','zh','','TTS',1,13,'啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊',''),(32,'https://res.cloudinary.com/difapxo01/video/upload/v1774653398/bcsd/tts-audio/hu-hu-khec-khec_ko.mp3?v=1774653398','ko','','TTS',1,14,'고양이들의 리더','울부짖어, 울부짖어, 울부짖어'),(33,'https://res.cloudinary.com/difapxo01/video/upload/v1774653401/bcsd/tts-audio/hu-hu-khec-khec_zh.mp3?v=1774653401','zh','','TTS',1,14,'猫的领袖','嚎叫，嚎叫，嚎叫'),(34,'https://res.cloudinary.com/difapxo01/video/upload/v1774630481/bcsd/tts-audio/test-tts-signal_vi.mp3','vi','','TTS',1,15,'NhatTruongNhatTruongNhatTruong',''),(35,'https://res.cloudinary.com/difapxo01/video/upload/v1774630484/bcsd/tts-audio/test-tts-signal_en.mp3','en','','TTS',1,15,'NhatTruongNhatTruongNhatTruong',''),(36,'https://res.cloudinary.com/difapxo01/video/upload/v1774630487/bcsd/tts-audio/test-tts-signal_ja.mp3','ja','','TTS',1,15,'ニャットチュオンニャットチュオンニャットチュオン',''),(37,'https://res.cloudinary.com/difapxo01/video/upload/v1774630489/bcsd/tts-audio/test-tts-signal_ko.mp3','ko','','TTS',1,15,'NhatTruongNhatTruongNhatTruong',''),(38,'https://res.cloudinary.com/difapxo01/video/upload/v1774630491/bcsd/tts-audio/test-tts-signal_zh.mp3','zh','','TTS',1,15,'日照日照日照',''),(39,'https://res.cloudinary.com/difapxo01/video/upload/v1774631572/bcsd/tts-audio/chua-vinh-khanh-co_zh.mp3','zh','','TTS',1,11,'这座拥有 150 多年历史的宝塔位于 Vinh Khanh 美食街的中心地带，当地人和小商贩每天清晨都会来这里烧香祈求平安。建筑风格典型的南方风格，红瓦屋顶，三进大门雄伟。','永庆寺宝塔'),(40,'https://res.cloudinary.com/difapxo01/video/upload/v1774631604/bcsd/tts-audio/cong-chao-pho-vinh-khanh_en.mp3','en','','TTS',1,12,'The symbolic welcome gate of Vinh Khanh night food street, designed with brilliant LED lights. It is a famous check-in point and also an ideal starting point to explore the entire culinary street. Lights up from 18:00 - 24:00.',''),(41,'https://res.cloudinary.com/difapxo01/video/upload/v1774631611/bcsd/tts-audio/cong-chao-pho-vinh-khanh_ja.mp3','ja','','TTS',1,12,'ヴィンカイン夜食街のシンボル的なウェルカムゲートを、鮮やかなLEDライトでデザイン。ここは有名なチェックインポイントであり、美食街全体を探索するのに理想的な出発点でもあります。点灯時間は18:00～24:00です。',''),(42,'https://res.cloudinary.com/difapxo01/video/upload/v1774631617/bcsd/tts-audio/cong-chao-pho-vinh-khanh_ko.mp3','ko','','TTS',1,12,'화려한 LED 조명으로 디자인된 빈칸 야식거리의 상징적인 환영문입니다. 이곳은 유명한 체크인 지점이자 전체 요리 거리를 탐험하기에 이상적인 출발점이기도 합니다. 점등 시간은 18:00~24:00입니다.',''),(43,'https://res.cloudinary.com/difapxo01/video/upload/v1774631620/bcsd/tts-audio/cong-chao-pho-vinh-khanh_zh.mp3','zh','','TTS',1,12,'永庆夜市美食街的标志性迎宾大门，采用绚丽的 LED 灯光设计。这里是著名的打卡点，也是探索整条美食街的理想起点。亮灯时间为 18:00 - 24:00。',''),(44,'https://res.cloudinary.com/difapxo01/video/upload/v1774631688/bcsd/tts-audio/goc-che-nuoc-ep-trai-cay_en.mp3','en','','TTS',1,10,'A familiar stop for locals after a meal with more than 30 types of traditional Southern sweet soup: semolina green bean sweet soup, Khuc Bach sweet soup, 3-color sweet soup... along with fresh tropical fruit juices, open from morning to night.',''),(45,'https://res.cloudinary.com/difapxo01/video/upload/v1774631695/bcsd/tts-audio/goc-che-nuoc-ep-trai-cay_ja.mp3','ja','','TTS',1,10,'地元の人々が食後に立ち寄り、セモリナ豆の甘いスープ、フックバッハの甘いスープ、3 色の甘いスープなど 30 種類以上の伝統的な南部の甘いスープと新鮮なトロピカル フルーツ ジュースを提供する、朝から夜まで営業しているおなじみの店です。',''),(46,'https://res.cloudinary.com/difapxo01/video/upload/v1774631702/bcsd/tts-audio/goc-che-nuoc-ep-trai-cay_ko.mp3','ko','','TTS',1,10,'30가지 이상의 전통적인 남부 달콤한 수프를 제공하는 식사 후 현지인들에게 친숙한 곳입니다: 양질의 거친 녹두 수프, 쿡박 달콤한 수프, 3색 달콤한 수프... 신선한 열대 과일 주스와 함께 아침부터 밤까지 영업합니다.',''),(47,'https://res.cloudinary.com/difapxo01/video/upload/v1774631707/bcsd/tts-audio/goc-che-nuoc-ep-trai-cay_zh.mp3','zh','','TTS',1,10,'当地人饭后熟悉的一站，这里有 30 多种传统南方甜汤：粗面粉绿豆甜汤、Khuc Bach 甜汤、三色甜汤……以及新鲜的热带果汁，从早到晚营业。',''),(48,'https://res.cloudinary.com/difapxo01/video/upload/v1774653384/bcsd/tts-audio/hu-hu-khec-khec_vi.mp3?v=1774653384','vi','','TTS',1,14,'lãnh đạo những con mèo',''),(49,'https://res.cloudinary.com/difapxo01/video/upload/v1774650900/bcsd/tts-audio/pho-am-thuc-vinh-khanh_ja.mp3?v=1774650900','ja','mien_nam','TTS',1,8,'ヴィン カインは、市内 4 区で最も有名なグルメ街です。ホーチミン。この場所には、新鮮な魚介類、牛肉麺、麺類から屋台の軽食まで、何百もの専門レストランが集まっています。朝から夜遅くまで賑わう雰囲気は、地元の人だけでなく、各地からの観光客も集まります。','? ヴィン カイン フード ストリート'),(50,'https://res.cloudinary.com/difapxo01/video/upload/v1774650891/bcsd/tts-audio/pho-am-thuc-vinh-khanh_en.mp3?v=1774650891','en','mien_nam','TTS',1,8,'Vinh Khanh is the most famous culinary street in District 4, City. HCM. This place brings together hundreds of specialty restaurants from fresh seafood, beef noodles, noodles to street snacks. The bustling atmosphere from morning to late night attracts both locals and tourists from everywhere..','? Vinh Khanh Food Street'),(51,'https://res.cloudinary.com/difapxo01/video/upload/v1774648897/bcsd/tts-audio/chua-vinh-khanh-co_ja.mp3','ja','mien_nam','TTS',1,11,'150 年以上の歴史を誇るこの塔は、ビン カイン料理街の中心部に位置しており、地元の人々や中小企業が毎朝早朝にお香を焚き、平和を祈るために集まります。典型的な南方様式の建築で、赤瓦の屋根、荘厳な三つ門の門が特徴です。','ヴィン カイン コ パゴダ'),(52,'https://res.cloudinary.com/difapxo01/video/upload/v1774648894/bcsd/tts-audio/chua-vinh-khanh-co_en.mp3','en','mien_nam','TTS',1,11,'The more than 150-year-old pagoda is located in the heart of Vinh Khanh culinary street, where local people and small businesses come to burn incense and pray for peace every early morning. The architecture is typical of Southern style, red tiled roof, majestic three-entrance gate.','Vinh Khanh Co Pagoda'),(53,'https://res.cloudinary.com/difapxo01/video/upload/v1774653393/bcsd/tts-audio/hu-hu-khec-khec_ja.mp3?v=1774653393','ja','mien_nam','TTS',1,14,'猫たちのリーダー','遠吠え、遠吠え、遠吠え'),(54,'https://res.cloudinary.com/difapxo01/video/upload/v1774653389/bcsd/tts-audio/hu-hu-khec-khec_en.mp3?v=1774653389','en','mien_nam','TTS',1,14,'leader of the cats','Howl, howl, howl');
/*!40000 ALTER TABLE `poi_media` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `pois`
--

DROP TABLE IF EXISTS `pois`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pois` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `description` longtext NOT NULL,
  `latitude` double NOT NULL,
  `longitude` double NOT NULL,
  `geofence_radius` int NOT NULL,
  `category` varchar(100) NOT NULL,
  `qr_code_data` varchar(512) NOT NULL,
