INSERT INTO `pois` VALUES (8,'? Phố Ẩm Thực Vĩnh Khánh','Vĩnh Khánh là con phố ẩm thực nổi tiếng bậc nhất Quận 4, TP. HCM. Nơi đây quy tụ hàng trăm quán ăn đặc sản từ hải sản tươi sống, bún bò, hủ tiếu cho đến các món ăn vặt đường phố. Không khí nhộn nhịp từ sáng đến đêm khuya thu hút cả người dân địa phương lẫn du khách thập phương..',10.7552,106.7038,200,'food','BCSD-POI-001',1,NULL),(9,'Quán Hải Sản Đêm Vĩnh Khánh','Khu ẩm thực hải sản đêm nổi tiếng nhất Quận 4 với các món ghẹ rang me, ốc hương xào, tôm nướng muối ớt được chế biến tươi ngon từ hải sản nhập trực tiếp mỗi ngày. Ngồi vỉa hè, không khí đường phố đặc trưng Sài Gòn.',10.7558,106.7042,50,'food','BCSD-POI-002',1,NULL),(10,'Góc Chè & Nước Ép Trái Cây','Điểm dừng chân quen thuộc của dân địa phương sau bữa ăn với hơn 30 loại chè truyền thống Nam Bộ: chè đậu xanh bột báng, chè khúc bạch, chè 3 màu... cùng các loại nước ép trái cây nhiệt đới tươi mát, mở cửa từ sáng đến đêm.',10.7545,106.7028,30,'food','BCSD-POI-003',1,NULL),(11,'Chùa Vĩnh Khánh Cổ','Ngôi chùa hơn 150 tuổi nằm giữa lòng phố ẩm thực Vĩnh Khánh, là nơi người dân địa phương và tiểu thương đến thắp hương cầu bình an mỗi sáng sớm. Kiến trúc đặc trưng phong cách Nam Bộ, mái ngói đỏ, cổng tam quan uy nghiêm.',10.7565,106.705,60,'historical','BCSD-POI-004',1,NULL),(12,'Cổng Chào Phố Vĩnh Khánh','Cổng chào biểu tượng của tuyến phố ẩm thực đêm Vĩnh Khánh, được thiết kế với đèn LED rực rỡ. Là điểm check-in nổi tiếng và cũng là điểm khởi đầu lý tưởng để khám phá toàn bộ tuyến phố ẩm thực. Sáng đèn từ 18:00 - 24:00.',10.754,106.7022,45,'cultural','BCSD-POI-005',1,NULL),(13,'Khu Bún Bò & Phở Sáng','áááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááááá