INSERT INTO `tours` VALUES (1,'Xuyên Đêm Phố Vĩnh Khánh',1,1,3,'Khám phá các hàng quán đêm sầm uất nhất phố Vĩnh Khánh.',90,'{\"en\": \"Explore the busiest night shops on Vinh Khanh street.\", \"ja\": \"ヴィン カイン通りで最も賑わう夜のお店を探索してみましょう。\", \"ko\": \"Vinh Khanh 거리에서 가장 바쁜 야간 상점을 둘러보세요.\", \"zh\": \"探索 Vinh Khanh 街上最繁忙的夜店。\"}','{\"en\": \"Through the Night on Vinh Khanh Street\", \"ja\": \"ヴィン・カイン通りの夜を徹して\", \"ko\": \"Vinh Khanh 거리의 밤을 통해\", \"zh\": \"永庆街的夜晚\"}',0,0),(2,'Văn Hóa Phố Quận 4',1,1,3,'Chùa cổ, gốc cây bồ đề và câu chuyện lịch sử khu dân cư lâu đời nhất Quận 4.',60,'{\"en\": \"Ancient pagoda, Bodhi tree and historical story of the oldest residential area in District 4.\", \"ja\": \"古代の塔、菩提樹、第 4 地区最古の住宅地の歴史物語。\", \"ko\": \"4군에서 가장 오래된 주거 지역에 대한 고대 탑, 보리수 및 역사적 이야기.\", \"zh\": \"第四区最古老住宅区的古塔、菩提树和历史故事。\"}','{\"en\": \"District 4 Street Culture\", \"ja\": \"4 地区ストリート カルチャー\", \"ko\": \"4구역 거리문화\", \"zh\": \"第四区街道文化\"}',0,0),(3,'Ẩm Thực Bình Dân Sài Gòn',0,1,3,'Lang thang và thưởng thức các món ăn bình dân nổi tiếng nhất Sài Gòn.',120,'{\"en\": \"Wander around and enjoy the most famous popular dishes in Saigon.\", \"ja\": \"散策して、サイゴンで最も有名な人気料理をお楽しみください。\", \"ko\": \"사이공에서 가장 유명한 인기 요리를 둘러보며 즐겨보세요.\", \"zh\": \"闲逛并享受西贡最著名的流行菜肴。\"}','{\"en\": \"Saigon Popular Cuisine\", \"ja\": \"サイゴンの人気料理\", \"ko\": \"사이공 인기 요리\", \"zh\": \"西贡流行美食\"}',1,10000000);
/*!40000 ALTER TABLE `tours` ENABLE KEYS */;
UNLOCK TABLES;

